package com.mvp.api_computacaografica.service;

import com.mvp.api_computacaografica.client.ApiComputacaoGraficaClient;
import com.mvp.api_computacaografica.dto.FotoRequestDto;
import com.mvp.api_computacaografica.dto.FotoResponseDto;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

@Service
public class FotoService {

    @Autowired
    ApiComputacaoGraficaClient client;

    public void buscarImagem(){
        try {
            FotoRequestDto request = new FotoRequestDto("");

            FotoResponseDto response = client.getFoto("b982015b7d32306d48c0", request);

            if (response != null && response.resposta() != null){
                System.out.println("Imagem enviada com sucesso");
            }
            else{
                System.out.println("Erro ao enviar imagem");
            }
        }catch (Exception e){
            throw new RuntimeException("Erro ao conectar com o servidor");
        }

    }
}
